module clock_gate(
  input CLK, // clock signal
  input EN, // enable signal
  input TE, // test enable signal
  output ENCLK // gated clock signal
);

  reg obf_gated_clk;

  always @(*) begin
    if (TE) begin
      obf_gated_clk = 1;
    end else if (EN) begin
      obf_gated_clk = CLK;
    end else begin
      obf_gated_clk = 0;
    end
  end

  assign ENCLK = obf_gated_clk;

endmodule
